/**
 * Commander Auto-Delegation — runs the Commander on tick intervals.
 *
 * Instead of executing actions immediately, auto-delegation proposes
 * actions that go into a pending queue. The player can approve, reject,
 * or let them auto-execute after a timeout.
 *
 * Works by temporarily swapping the Commander's workerSend function
 * during auto-delegation runs to capture proposed messages.
 */

import { askCommander, isCommanderEnabled, setCommanderWorkerSend } from './commanderService';
import type { CommanderResult } from './commanderService';
import type { GameStateSummary } from './gameState';
import type { MainToWorkerMessage } from '../sim/messages';
import type { SerializedCommanderState } from '../sim/saveLoad';
import { recordInteraction, serializeSpectrum, restoreSpectrum } from './ariaSpectrum';
import type { InteractionRecord } from './ariaSpectrum';

// ── Pending action types ─────────────────────────────────────────────────────

export interface PendingAction {
  id: number;
  /** Human-readable description from tool result */
  description: string;
  /** The sim message to send if approved */
  message: MainToWorkerMessage;
  /** Tick when this was proposed */
  proposedAtTick: number;
  /** Wall-clock time when this was proposed (Date.now()), for time-to-approve measurement */
  proposedAtMs: number;
  /** ARIA's reasoning for this batch */
  reasoning: string;
}

// ── State ────────────────────────────────────────────────────────────────────

let delegationEnabled = false;
let delegationInterval = 200; // ticks between auto-delegation runs
let lastDelegationTick = 0;
let running = false;
let nextActionId = 1;

const pendingActions: PendingAction[] = [];
const MAX_PENDING = 10;

/** The real worker send function (for approved actions + restoring after capture) */
let realWorkerSendFn: ((msg: MainToWorkerMessage) => void) | null = null;

/** Callback to build current game state snapshot */
let buildStateFn: (() => GameStateSummary) | null = null;

/** Callback when pending actions change (for UI updates) */
let onPendingChangeFn: ((actions: readonly PendingAction[]) => void) | null = null;

// Capture buffer used during auto-delegation runs
let captureBuffer: Array<{ description: string; message: MainToWorkerMessage }> = [];
let capturing = false;
let captureTick = 0;

// ── Configuration ────────────────────────────────────────────────────────────

export function setDelegationEnabled(enabled: boolean): void {
  delegationEnabled = enabled;
}

export function isDelegationEnabled(): boolean {
  return delegationEnabled;
}

export function setDelegationInterval(ticks: number): void {
  delegationInterval = Math.max(50, ticks);
}

export function getDelegationInterval(): number {
  return delegationInterval;
}

export function setDelegationBuildState(fn: () => GameStateSummary): void {
  buildStateFn = fn;
}

export function setDelegationWorkerSend(fn: (msg: MainToWorkerMessage) => void): void {
  realWorkerSendFn = fn;
}

export function onPendingActionsChange(fn: (actions: readonly PendingAction[]) => void): void {
  onPendingChangeFn = fn;
}

// ── Public API ───────────────────────────────────────────────────────────────

export function getPendingActions(): readonly PendingAction[] {
  return pendingActions;
}

/**
 * Called every tick from the main loop. Checks if it's time to auto-delegate.
 */
export function tickDelegation(currentTick: number): void {
  if (!delegationEnabled || !isCommanderEnabled() || running) return;
  if (!buildStateFn || !realWorkerSendFn) return;
  if (currentTick - lastDelegationTick < delegationInterval) return;
  if (pendingActions.length >= MAX_PENDING) return;

  lastDelegationTick = currentTick;
  running = true;

  const state = buildStateFn();
  void runDelegation(state, currentTick).finally(() => {
    running = false;
  });
}

/**
 * Approve a pending action — execute it and remove from queue.
 */
export function approveAction(actionId: number): boolean {
  const idx = pendingActions.findIndex((a) => a.id === actionId);
  if (idx === -1 || !realWorkerSendFn) return false;

  const action = pendingActions[idx];
  realWorkerSendFn(action.message);

  // Record proposal response for spectrum tracking
  const elapsedMs = Date.now() - action.proposedAtMs;
  recordInteraction(classifyApproval(action.proposedAtTick, elapsedMs));

  pendingActions.splice(idx, 1);
  notifyChange();
  return true;
}

/**
 * Approve all pending actions.
 */
export function approveAllActions(): void {
  if (!realWorkerSendFn) return;

  // Bulk approve is a strong overtrust signal
  if (pendingActions.length > 0) {
    const tick = pendingActions[0].proposedAtTick;
    recordInteraction({
      tick,
      dimension: 'proposalResponse',
      direction: -1,
      magnitude: 1.0,
      source: 'bulk_approve',
    });
  }

  for (const action of pendingActions) {
    realWorkerSendFn(action.message);
  }
  pendingActions.length = 0;
  notifyChange();
}

/**
 * Reject a pending action — remove without executing.
 */
export function rejectAction(actionId: number): boolean {
  const idx = pendingActions.findIndex((a) => a.id === actionId);
  if (idx === -1) return false;

  const action = pendingActions[idx];
  // Rejection is an undertrust signal
  recordInteraction({
    tick: action.proposedAtTick,
    dimension: 'proposalResponse',
    direction: 1,
    magnitude: 0.7,
    source: 'reject',
  });

  pendingActions.splice(idx, 1);
  notifyChange();
  return true;
}

/**
 * Reject all pending actions.
 */
export function rejectAllActions(): void {
  pendingActions.length = 0;
  notifyChange();
}

/** Whether an auto-delegation run is actively capturing (manual input should be blocked). */
export function isCapturing(): boolean {
  return capturing;
}

/** Reset state (for testing or game restart). */
export function resetDelegation(): void {
  pendingActions.length = 0;
  lastDelegationTick = 0;
  running = false;
  nextActionId = 1;
  notifyChange();
}

export function serializeDelegationState(): SerializedCommanderState {
  const spectrum = serializeSpectrum();
  return {
    pendingActions: pendingActions.map((a) => ({
      id: a.id,
      description: a.description,
      message: a.message as unknown as Record<string, unknown>,
      proposedAtTick: a.proposedAtTick,
      proposedAtMs: a.proposedAtMs,
      reasoning: a.reasoning,
    })),
    nextActionId,
    delegationEnabled,
    spectrumDimensions: spectrum.spectrumDimensions,
    dialogueStage: spectrum.dialogueStage,
    interactionHistory: spectrum.interactionHistory,
  };
}

export function restoreDelegationState(state: SerializedCommanderState): void {
  pendingActions.length = 0;
  for (const a of state.pendingActions) {
    pendingActions.push({
      id: a.id,
      description: a.description,
      message: a.message as unknown as MainToWorkerMessage,
      proposedAtTick: a.proposedAtTick,
      proposedAtMs: a.proposedAtMs ?? Date.now(),
      reasoning: a.reasoning,
    });
  }
  nextActionId = state.nextActionId;
  delegationEnabled = state.delegationEnabled;

  // Restore spectrum state if present
  if (state.spectrumDimensions) {
    restoreSpectrum({
      spectrumDimensions: state.spectrumDimensions,
      dialogueStage: state.dialogueStage ?? 'advisor',
      interactionHistory: (state.interactionHistory ?? []) as InteractionRecord[],
    });
  }

  notifyChange();
}

/** Test helper — manually add a pending action without running the Commander. */
export function _addPendingForTest(description: string, message: MainToWorkerMessage, tick: number, proposedAtMs?: number): void {
  if (pendingActions.length >= MAX_PENDING) return;
  pendingActions.push({
    id: nextActionId++,
    description,
    message,
    proposedAtTick: tick,
    proposedAtMs: proposedAtMs ?? Date.now(),
    reasoning: '',
  });
}

// ── Internals ────────────────────────────────────────────────────────────────

/**
 * Classify an approval into a spectrum InteractionRecord based on wall-clock
 * time-to-approve. <2s = auto-approve (overtrust), >10s = engaged (partnership),
 * 2-10s = neutral.
 */
function classifyApproval(tick: number, elapsedMs: number): InteractionRecord {
  if (elapsedMs < 2000) {
    // Auto-approve: overtrust signal
    return { tick, dimension: 'proposalResponse', direction: -1, magnitude: 0.8, source: 'approve' };
  } else if (elapsedMs > 10000) {
    // Engaged review: partnership signal (neutral direction)
    return { tick, dimension: 'proposalResponse', direction: 0, magnitude: 0.6, source: 'approve' };
  } else {
    // Neutral range
    return { tick, dimension: 'proposalResponse', direction: 0, magnitude: 0.3, source: 'approve' };
  }
}

const AUTO_DELEGATION_QUERY = `Review the current operation status. If there are idle robots, resource shortages, missing buildings, or research opportunities, take appropriate actions. Prioritize: survival > production > research > expansion. If everything looks optimal, take no actions.`;

async function runDelegation(state: GameStateSummary, currentTick: number): Promise<void> {
  if (!realWorkerSendFn) return;

  // Swap workerSend to capture mode — messages go to captureBuffer instead of worker
  captureBuffer = [];
  capturing = true;
  captureTick = currentTick;

  setCommanderWorkerSend((msg: MainToWorkerMessage) => {
    if (capturing) {
      captureBuffer.push({ description: '', message: msg });
    } else {
      realWorkerSendFn!(msg);
    }
  });

  try {
    const result: CommanderResult = await askCommander(AUTO_DELEGATION_QUERY, state);

    // Stop capturing and restore real send function
    capturing = false;
    setCommanderWorkerSend(realWorkerSendFn);

    if (result.error) {
      console.warn('[Delegate] Commander error:', result.error);
      return;
    }

    if (captureBuffer.length === 0) return;

    // Match captured messages with action descriptions from result
    for (let i = 0; i < captureBuffer.length; i++) {
      const captured = captureBuffer[i];
      captured.description = result.actions[i] ?? describeMessage(captured.message);
    }

    // Add to pending queue
    const nowMs = Date.now();
    for (const captured of captureBuffer) {
      if (pendingActions.length >= MAX_PENDING) break;
      pendingActions.push({
        id: nextActionId++,
        description: captured.description,
        message: captured.message,
        proposedAtTick: currentTick,
        proposedAtMs: nowMs,
        reasoning: result.explanation,
      });
    }

    notifyChange();
  } catch (err) {
    // Restore real send function on error
    capturing = false;
    setCommanderWorkerSend(realWorkerSendFn);
    console.warn('[Delegate] Auto-delegation failed:', err);
  }
}

/** Fallback description for a worker message. */
function describeMessage(msg: MainToWorkerMessage): string {
  switch (msg.type) {
    case 'sim:enqueue_build':
      return `Queue robot type ${msg.payload.robotType} for production`;
    case 'sim:build_building':
      return `Build building type ${msg.payload.buildingType}`;
    case 'sim:start_research':
      return `Start research on "${msg.payload.nodeId}"`;
    case 'sim:enqueue_recipe':
      return `Queue refining recipe "${msg.payload.recipeId}"`;
    case 'sim:robot_order':
      return `Order robot ${msg.payload.robotEid} to ${msg.payload.order}`;
    default:
      return `Execute: ${msg.type}`;
  }
}

function notifyChange(): void {
  if (onPendingChangeFn) {
    onPendingChangeFn([...pendingActions]);
  }
}
